import Transition from './Transition';
import StateMachine from './StateMachine';
import InternalTransition from './InternalTransition';
import TimeoutTransition from './TimeoutTransition';


export interface TypedEventLike {
	name: string;
	on: (handle: (x?: any) => void) => any;
	removeListener: (handle: (x?: any) => void) => any;
	emit: (x?: any) => any;
}

export default class State {

	public _isCurrent = false;
	public transitions: Transition[] = [];
	public _lastIncomingResults: any;

	/**
	 * Method called on entry into the state
	 */
	public onEntry: (transition: Transition, result?: any) => void;

	/**
	 * Method called on exit from the state
	 */
	public onExit: (transition: Transition) => void;

	/**
	 * Method called on update from the StateMachine (if it is being called in an update loop)
	 */
	public onUpdate: () => void;

	/**
	 * Method called if the StateMachine is externally interrupted.
	 */
	public onStop: () => void;

	/**
	 * Method called as last part of exiting state, allows for
	 * asynchronous cleanup in state.
	 */
	public postExit: (done: () => void) => void;

	private _internalTransitions = new Map<State, InternalTransition>();
	private _events = new Map<string, Function>();
	private _typedEvents = new Map<TypedEventLike, (x?: any) => void>();

	constructor(public sm: StateMachine, public name: string, transitions?: Transition[]) {
		sm._addState(this);
		if (transitions) {
			this.addTransition(transitions);
		}
	}

	addTransition(transitions: Transition[]);
	addTransition(transition: Transition);

	addTransition(transition: any): State {
		if (Array.isArray(transition)) {
			transition.forEach(trans => {
				this._addTransition(trans);
			});
		}
		else {
			this._addTransition(transition);
		}
		return this;
	}

	_addTransition(transition: Transition) {
		if (transition.getSourceState()) {
			throw new Error(`This transition has already been assigned to a source state`);
		}

		transition._setSourceState(this);
		this.transitions.push(transition);
		if (transition instanceof InternalTransition) {
			if (this._internalTransitions.has(transition.getDestinationState())) {
				throw new Error(`State already has internal transition to destination` +
					` state: ${this._internalTransitions.get(transition.getDestinationState())}`);
			}
			this._internalTransitions.set(transition.getDestinationState(), transition);
		}
	}

	addEventTransition(event: string, destState: State): State {
		let trans = new Transition('Event: '+event, destState);

		const eventHandler = (result) => {
			if (this._isCurrent) {
				trans.trigger(result);
			}
		};

		this.sm.on(event, eventHandler);

		this._events.set(event, eventHandler);
		this.addTransition(trans);
		return this;
	}

	addTypedEventTransition(event: TypedEventLike, destState: State): State {
		let trans = new Transition('TEvent: '+event.name, destState);

		const eventHandler = result => {
			if (this._isCurrent) {
				trans.trigger(result);
			}
		};

		event.on(eventHandler);

		this._typedEvents.set(event, eventHandler);
		this.addTransition(trans);
		return this;
	}

	_enter(transition: Transition, result?: any) {
		this._isCurrent = true;
		this._lastIncomingResults = result;

		// We evaluate this state's onEntry method
		if (this.onEntry) {
			this.onEntry(transition, result);
		}

		// We evaluate this state's transitions' onEntry methods
		for (let trans of this.transitions) {
			trans._enter();
		}
	}

	_exit(transition: Transition, done: () => void) {
		if (this.onExit) {
			this.onExit(transition);
		}

		for (let trans of this.transitions) {
			trans._exit();
		}

		this._isCurrent = false;

		if (this.postExit) {
			this.postExit(done);
		}
		else {
			done();
		}
	}

	_stop(): void {
		this.transitions.forEach( trans => {
			if (trans instanceof TimeoutTransition) {
				trans.stop();
			}
		});

		if (this.onStop) {
			this.onStop();
		}
	}

	/**
	 * Retrieves the last result that was provided to this state upon entry
	 * @returns {Object}
	 */
	getLastIncomingResult() {
		return this._lastIncomingResults;
	}

	/**
	 * Transitions to a destination state. An `InternalTransition` needs to
	 * have been added from this state to the destination state
	 * Note: If this state is not the current state then an exception is thrown
	 * @param {State} state The desired next state
	 * @param {Object} result Optional result object to pass to next state
	 */
	transitionTo(state: State, result?: any) {
		let trans = this._internalTransitions.get(state);
		if (!trans) {
			throw new Error(`State has no internal transition to state ${state}`);
		}

		if (!this._isCurrent) {
			throw new Error(`Can't transition out of state that isn't current. ` +
				`This state: '${this}', target state: '${state}', ` +
				`current state: '${this.sm.current}'`);
		}

		trans.trigger(result);
	}

	/**
	 * Destroys the state. Should be called when state machine is getting discarded
	 */
	destroy(): void {
		// this._isCurrent = false;
		this._events.forEach( (handler, eventName) => {
			this.sm.removeListener(eventName, handler);
		});
		this._events.clear();
		this._typedEvents.forEach( (handler, event) => {
			event.removeListener(handler);
		});
		this._typedEvents.clear();
		this.transitions.forEach( trans => trans.destroy() );
		// this.transitions = [];
		// this._internalTransitions.clear();
		this._lastIncomingResults = null;
		this.onEntry = null;
		this.onExit = null;
		this.onUpdate = null;
		this.onStop = null;
		this.postExit = null;
	}

	toString() {
		return 'State: ' + this.name;
	}
}